INSERT INTO `exams` (`id`, `title`, `duration`, `questions`, `type`, `modelAnswerFile`, `isActive`, `createdAt`, `updatedAt`, `courseId`, `instructorId`, `examDate`) VALUES
('clexam001', 'CS101 Midterm Exam', 120, '[{\"type\": \"SHORT_ANSWER\", \"points\": 10, \"question\": \"What is a variable in programming?\", \"model_answer\": \"A variable is a named storage location in memory that holds a value which can be changed during program execution.\"}, {\"type\": \"SHORT_ANSWER\", \"points\": 15, \"question\": \"Explain the difference between while and for loops.\", \"model_answer\": \"A while loop continues as long as a condition is true, while a for loop is typically used when the number of iterations is known beforehand and includes initialization, condition, and increment in one line.\"}, {\"type\": \"SHORT_ANSWER\", \"points\": 25, \"question\": \"Write a function to calculate factorial.\", \"model_answer\": \"def factorial(n):\\n    if n <= 1:\\n        return 1\\n    return n * factorial(n-1)\"}]', 'MIXED', NULL, 1, '2024-10-25 10:00:00.000', '2024-10-25 10:00:00.000', 'clcourse001', 'cmhfehuu200027kic5hrxn5rm', '2024-11-15 23:59:59.000'),
('clexam002', 'CS101 Final Exam', 180, '[{\"type\": \"SHORT_ANSWER\", \"points\": 20, \"question\": \"What is object-oriented programming?\", \"model_answer\": \"OOP is a programming paradigm based on objects that contain data and code. Key principles include encapsulation, inheritance, polymorphism, and abstraction.\"}, {\"type\": \"TRUE_FALSE\", \"points\": 5, \"question\": \"Python uses dynamic typing. True or False?\", \"model_answer\": \"True\"}, {\"type\": \"SHORT_ANSWER\", \"points\": 30, \"question\": \"Implement a class for a bank account with deposit and withdraw methods.\", \"model_answer\": \"class BankAccount:\\n    def __init__(self, balance=0):\\n        self.balance = balance\\n    def deposit(self, amount):\\n        self.balance += amount\\n    def withdraw(self, amount):\\n        if amount <= self.balance:\\n            self.balance -= amount\\n            return True\\n        return False\"}]', 'MIXED', NULL, 1, '2024-11-01 10:00:00.000', '2024-11-01 10:00:00.000', 'clcourse001', 'cmhfehuu200027kic5hrxn5rm', '2024-12-20 23:59:59.000'),
('clexam003', 'CS202 Quiz 1 - Arrays and Lists', 45, '[{\"type\": \"MCQ\", \"points\": 10, \"options\": [\"O(1)\", \"O(n)\", \"O(log n)\", \"O(n^2)\"], \"question\": \"What is the time complexity of accessing an element in an array by index?\", \"model_answer\": \"O(1)\"}, {\"type\": \"TRUE_FALSE\", \"points\": 5, \"question\": \"A linked list allows O(1) insertion at the beginning. True or False?\", \"model_answer\": \"True\"}, {\"type\": \"SHORT_ANSWER\", \"points\": 15, \"question\": \"Explain the difference between arrays and linked lists.\", \"model_answer\": \"Arrays store elements in contiguous memory with O(1) access time but O(n) insertion/deletion. Linked lists use non-contiguous memory with O(n) access but O(1) insertion/deletion at known positions.\"}]', 'MIXED', NULL, 1, '2024-10-20 09:00:00.000', '2024-10-20 09:00:00.000', 'clcourse003', 'cmhfehuu200027kic5hrxn5rm', '2024-11-08 23:59:59.000'),
('clexam004', 'CS202 Midterm - Trees and Graphs', 90, '[{\"type\": \"SHORT_ANSWER\", \"points\": 15, \"question\": \"What is a binary search tree?\", \"model_answer\": \"A binary search tree is a binary tree where for each node, all values in the left subtree are less than the node value, and all values in the right subtree are greater.\"}, {\"type\": \"SHORT_ANSWER\", \"points\": 25, \"question\": \"Implement BFS traversal for a graph.\", \"model_answer\": \"from collections import deque\\ndef bfs(graph, start):\\n    visited = set()\\n    queue = deque([start])\\n    visited.add(start)\\n    while queue:\\n        vertex = queue.popleft()\\n        for neighbor in graph[vertex]:\\n            if neighbor not in visited:\\n                visited.add(neighbor)\\n                queue.append(neighbor)\"}]', 'MIXED', NULL, 1, '2024-10-28 09:00:00.000', '2024-10-28 09:00:00.000', 'clcourse003', 'cmhfehuu200027kic5hrxn5rm', '2024-11-25 23:59:59.000'),
('clexam005', 'MATH201 Calculus Quiz', 60, '[{\"type\": \"SHORT_ANSWER\", \"points\": 10, \"question\": \"Integrate x^2 dx\", \"model_answer\": \"(x^3)/3 + C\"}, {\"type\": \"SHORT_ANSWER\", \"points\": 15, \"question\": \"What is the fundamental theorem of calculus?\", \"model_answer\": \"The fundamental theorem of calculus links differentiation and integration, stating that integration is the inverse of differentiation.\"}]', 'SHORT_ANSWER', NULL, 1, '2024-10-15 14:00:00.000', '2024-10-15 14:00:00.000', 'clcourse005', 'cmhfehuu200027kic5hrxn5rm', '2024-11-10 23:59:59.000'),
('cmkr3brvm00017ks4mjq8fhb1', 'Database Systems Final', NULL, '\"[{\\\"questionId\\\":\\\"1.1\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"1. A set of rules that governs data communication\\\\n(a) Standards\\\\n(b) Protocols\\\\n(c) Governors\\\\n(d) None of the above\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"(b) Protocols\\\"},{\\\"questionId\\\":\\\"1.2\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"2. Two devices are in network if\\\\n(a) A process in one device is able to exchange information with a process in another device\\\\n(b) A process is running on both devices\\\\n(c) PIDS of the processes running of different devices are same\\\\n(d) None of the above\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"(a) A process in one device is able to exchange information with a process in another device\\\"},{\\\"questionId\\\":\\\"1.3\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"3. Which topology covers security, robust and eliminating traffic factor?\\\\n(a) Mesh\\\\n(b) Ring\\\\n(c) Star\\\\n(d) Bus\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"(a) Mesh\\\"},{\\\"questionId\\\":\\\"1.4\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"4. What does Router do in a network?\\\\n(a) Forwards a packet to all outgoing links\\\\n(b) Forwards a packet to the next free outgoing link\\\\n(c) Determines on which outing link a packet is to be forwarded\\\\n(d) Forwards a packet to all outgoing links except the originated link\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"(c) Determines on which outing link a packet is to be forwarded\\\"},{\\\"questionId\\\":\\\"1.5\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"5. Which of the following protocols provides a connection-oriented reliable service for sending mes- sages\\\\n(a) TCP\\\\n(b) IP\\\\n(c) UDP\\\\n(d) All of the above\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"(a) TCP\\\"},{\\\"questionId\\\":\\\"1.6\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"6. What does protocol defines?\\\\n(a) Protocol defines what data is communicated\\\\n(b) Protocol defines how data is communicated\\\\n(c) Protocol defines when data is communicated\\\\n(d) All of the above\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"(d) All of the above\\\"},{\\\"questionId\\\":\\\"1.7\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"7. TCP/IP layer is equivalent to combined Session, Presentation and\\\\n(a) Network layer\\\\n(b) Application layer\\\\n(c) Transport layer\\\\n(d) Physical layer\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"(b) Application layer\\\"},{\\\"questionId\\\":\\\"1.8\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"8. Which of them is not an appropriate method of router security?\\\\n(a) Unused ports should be blocked\\\\n(b) Unused interfaces and services should be disabled\\\\n(c) Routing protocol needs to be programmed by security experts\\\\n(d) Packet filtering needs to be enabled\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"(c) Routing protocol needs to be programmed by security experts\\\"},{\\\"questionId\\\":\\\"2.a\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"Draw the OSI model and define the function of each layer?\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"Application: To allow access to net. resources\\\\nPresentation: To Translate, encrypt, and Compless data\\\\nSession: To establish, manage, and terminate Sessions\\\\nTransport: To Provide reliable process to process message delivery\\\\n\\\\nApplication\\\\nPresentation\\\\nSession\\\\nTransport\\\\nNetwork\\\\nData Link\\\\nPhysical\\\\n\\\\n7\\\\n6\\\\n5\\\\n4\\\\n3\\\\n2\\\\n1\\\\n\\\\nNetwork: To move Packets from Source to destination\\\\nDatalink: To organize bits into frames to provide hop-to-hop delivery.\\\\nPhysical, To transmit bits over a medium to provide mechanical and electrical specifications.\\\"},{\\\"questionId\\\":\\\"2.b\\\",\\\"type\\\":\\\"Calculation\\\",\\\"question\\\":\\\"Suppose that a low-pass communications system has a 1 MHz bandwidth. What is an attainable bit rate using 8-level pulses? What is the Shannon capacity of this channel if the SNR is 20 dB?\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"Solution\\\\nPulses Can be sent over this system at rate achieve Nyquist theory = 2 million pulses Per sec.\\\\n8 level Carries 3 bits/Pulse\\\\n: bit rate = 6 Mbps\\\\n: Shannon Capacity:\\\\nC = 10^6 \\\\\\\\log_2 (1+100)\\\\n= 6.6\\\\n6.6 Mbps\\\\n#\\\"},{\\\"questionId\\\":\\\"3.1\\\",\\\"type\\\":\\\"Calculation\\\",\\\"question\\\":\\\"1. Total delay to deliver the file using circuit-switching.\\\",\\\"questionGrade\\\":1.25,\\\"answer\\\":\\\"Solution\\\\nFile to be transmitted along Path bet. Source & dest. over 3 Switches\\\\nTotal delay = tsetup + tr(data) + t release\\\\n= 1 + \\\\\\\\frac{K}{4 \\\\\\\\times 10^6} + 1\\\\n= 2 + \\\\\\\\frac{K}{4 \\\\\\\\times 10^6} Sec.\\\"},{\\\"questionId\\\":\\\"3.2\\\",\\\"type\\\":\\\"Calculation\\\",\\\"question\\\":\\\"2. Total delay to deliver the file using packet-switching. Assume that source sends one packet, waits until an acknowledgement is received (assuming that this takes 10 ms after the packet has been completely delivered to the destination), then sends the next packet, and so on.\\\",\\\"questionGrade\\\":1.25,\\\"answer\\\":\\\"2 Packet switching with ack. with Packet size = 1 kbit = 1000 bits( Payload) + 24 bit (header)\\\\nTime to transfer 1 Packet = 4tp + 4 tr = 4 \\\\\\\\times 2 + 4 \\\\\\\\times \\\\\\\\frac{1024}{4 \\\\\\\\times 10^6} = 9.042 msec.\\\\nTime needed to transfer this file = \\\\\\\\frac{K}{1000} \\\\\\\\times (9.042 + 10) msec.\\\"},{\\\"questionId\\\":\\\"3.3\\\",\\\"type\\\":\\\"Calculation\\\",\\\"question\\\":\\\"3. Total delay to deliver the file using packet-switching. Assume that the source sends all packets back to back, without waiting for acknowledgments.\\\",\\\"questionGrade\\\":1.25,\\\"answer\\\":\\\"Time needed to transfer this file = 9.042 + 0.256 \\\\\\\\times (\\\\\\\\frac{K}{1000} - 1) msec.\\\"},{\\\"questionId\\\":\\\"3.4\\\",\\\"type\\\":\\\"Calculation\\\",\\\"question\\\":\\\"4. For what values of K is scenario (1) faster than scenario (3)?\\\",\\\"questionGrade\\\":1.25,\\\"answer\\\":\\\"K > 331.78 \\\\\\\\times 10^6 bits\\\"},{\\\"questionId\\\":\\\"4.1\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"What are the main components of delay when we use packet switching?\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"* Processing (Nodal) delay\\\\n* Queving delay\\\\n* Transmission delay\\\\n* Propagation delay\\\"},{\\\"questionId\\\":\\\"4.2\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"What is the difference between transmission delay and propagation delay? How is propagation delay affected if the length of the packet is increased?\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"* Transmission delay is the time needed to put the entire Packet on the link and is dependent on the length of the Packet, while the Propagation delay is needed time for one bit to reach to the other end of the link.\\\\n* Propagation delay is just a function of link length and its Physical Characteristics, so it is not affected.\\\"},{\\\"questionId\\\":\\\"4.3\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"Extra Credit: Draw a picture (scientific or fun)! If it makes me laugh, you get two points. If I don\'t laugh, you get -2 points. Be Creative!\\\",\\\"questionGrade\\\":null,\\\"answer\\\":\\\"255\\\"},{\\\"questionId\\\":\\\"5.0\\\",\\\"type\\\":\\\"Calculation\\\",\\\"question\\\":\\\"Interface 0:\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"0 0 0 0\\\\n0011\\\\nRange = 2^6 = 64 address\\\\n0-63\\\"},{\\\"questionId\\\":\\\"5.1\\\",\\\"type\\\":\\\"Calculation\\\",\\\"question\\\":\\\"Interface 1:\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"0100\\\\n1010\\\\n5\\\\nb\\\\no o o o\\\\n11 11\\\\nRange = 2^5 = 32 address\\\\n67-95\\\"},{\\\"questionId\\\":\\\"5.2\\\",\\\"type\\\":\\\"Calculation\\\",\\\"question\\\":\\\"Interface 2:\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"0110 0000\\\\n1011 1111\\\\nRange = 2^4 + 2^4 = 96 address\\\\n96 -> 191\\\"},{\\\"questionId\\\":\\\"5.3\\\",\\\"type\\\":\\\"Calculation\\\",\\\"question\\\":\\\"Interface 3:\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"1100 0000\\\\n1111 1111\\\\nRange = 2^6 = 64 address\\\\n196-255\\\"},{\\\"questionId\\\":\\\"6.1\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"1- 2x speedup on a computer with 10 processors is a good result.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"6.2\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"2- Multi-threading decreases the run time of any single thread.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"False\\\"},{\\\"questionId\\\":\\\"6.3\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"3- In Non-uniform memory access (NUMA), all processors can access any memory location, but the cost of memory access is different for different processors.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"6.4\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"4- A common modern practice is to use a message-passing programming model within a multi-core node of a cluster and to use a shared address space programming model between nodes.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"False\\\"},{\\\"questionId\\\":\\\"6.5\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"5- A consensus algorithm is a process in computer science used to achieve agreement on a single data value among distributed processes or systems.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"6.6\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"6- Parallel programming models provide abstractions that admit many possible implementations.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"6.7\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"7- The semi-static assignment is preferred when the cost of work is predictable for the near-term future.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"6.8\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"8- The main goal of weak scaling is to run the same problem size faster.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"False\\\"},{\\\"questionId\\\":\\\"6.9\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"9- In pipelined communication, occupancy determines the communication rate.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"6.10\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"10- In the case of implementing sync using greedy policy, the last thread to reach the join point continues execution after sync.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"}]\"', 'MIXED', 'https://ai-exam-grader-pdfs.s3.eu-central-1.amazonaws.com/model-answers/cmkr3brvm00017ks4mjq8fhb1/model-answer.pdf', 1, '2026-01-23 16:23:51.774', '2026-01-23 16:23:53.000', 'clcourse008', 'cmhfehuu200027kic5hrxn5rm', '2026-01-23 00:00:00.000'),
('cmksw8ren00017khcjonxabsg', 'Security Final', NULL, '\"[{\\\"questionId\\\":\\\"1.1\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"1. An employee receives a highly personalized email that references internal projects and\\\\ncomes from an address that visually matches a trusted domain. The attacker succeeded by\\\\nexploiting human behavior, not a software bug. From the lecture\'s perspective, which statement\\\\nbest explains why this attack is difficult to prevent using technical controls alone?\\\\nA. Phishing primarily exploits vulnerabilities in SMTP that cannot be fixed\\\\nB. Phishing targets the human attack surface, which remains vulnerable even when systems\\\\nare technically secure\\\\nC. Phishing is an availability attack that overwhelms users with messages\\\\nD. Phishing bypasses encryption by breaking cryptographic algorithms\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"(B) Phishing targets the human attack surface, which remains vulnerable even when systems\\\\nare technically secure\\\"},{\\\"questionId\\\":\\\"1.2\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"2. You are threat-modeling a student portal. A developer claims: “If we encrypt all traffic, we\\\\nhave solved confidentiality, integrity, and authentication.\\\\\\\" Which critique best matches the\\\\nlecture\'s separation of services and mechanisms?\\\\nA. Encryption is a mechanism mainly for confidentiality; integrity and authentication require\\\\nadditional mechanisms/services (e.g., hashes/MACs, signatures, authentication exchange)\\\\nB. Encryption provides confidentiality and integrity, but never availability\\\\nC. Encryption is a security service; hashes and signatures are mechanisms\\\\nD. If encryption is strong (AES-256), then authenticity is guaranteed by Kerckhoffs\'s Principle\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"(A) Encryption is a mechanism mainly for confidentiality; integrity and authentication require\\\\nadditional mechanisms/services (e.g., hashes/MACs, signatures, authentication exchange)\\\"},{\\\"questionId\\\":\\\"1.3\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"3. A SOC analyst observes encrypted traffic between a user and a server but infers sensitive\\\\noperational details from who communicates, when, and how much. Which pairing is most\\\\naccurate?\\\\nA. Active attack; data modification; threatens integrity\\\\nB. Passive attack; traffic analysis; threatens confidentiality\\\\nC. Active attack; masquerade; threatens authentication\\\\nD. Passive attack; release of message contents; threatens availability\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"(B) Passive attack; traffic analysis; threatens confidentiality\\\"},{\\\"questionId\\\":\\\"1.4\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"4. During an incident, thousands of TCP connections are stuck in a \\\\\\\"pending\\\\\\\" state because\\\\nclients sent SYNs but never completed the handshake. Which statement is the best conceptual\\\\nclassification across the lecture\'s frameworks?\\\\nA. It is primarily a confidentiality attack because attackers observe server responses\\\\nB. It is an active attack (DoS) targeting availability by exploiting half-open TCP state\\\\nC. It is a passive attack because no packets are modified\\\\nD. It is a data modification attack because SYN-ACK messages are forged\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"(B) It is an active attack (DoS) targeting availability by exploiting half-open TCP state\\\"},{\\\"questionId\\\":\\\"1.5\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"5. A team wants to prevent replay of a captured \\\\\\\"valid login request\\\\\\\" in a wireless access\\\\nsystem. Which mechanism/service alignment best matches the lecture\'s recap logic?\\\\nA. Confidentiality service using encryption, because encryption always prevents replay\\\\nB. Authentication service using authentication exchange (e.g., challenge-response/OTP),\\\\nbecause freshness is verified\\\\nC. Nonrepudiation service using hashing, because hashes prevent duplicates\\\\nD. Integrity service using traffic padding, because padding hides repeated patterns\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"(B) Authentication service using authentication exchange (e.g., challenge-response/OTP),\\\\nbecause freshness is verified\\\"},{\\\"questionId\\\":\\\"1.6\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"6. An organization uses RBAC and ABAC together. A user is assigned the role \\\\\\\"Doctor” (RBAC),\\\\nbut access is granted only if the device is patched and the login is from the local network\\\\n(ABAC). What is the most accurate interpretation?\\\\nA. RBAC is redundant because ABAC can fully replace roles without trade-offs\\\\nB. ABAC is enforcing fine-grained, context-dependent constraints on top of role-based\\\\npermissions\\\\nC. RBAC is enforcing device health, while ABAC enforces job functions\\\\nD. This is DAC, because access ultimately depends on the user\'s discretion\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"(B) ABAC is enforcing fine-grained, context-dependent constraints on top of role-based\\\\npermissions\\\"},{\\\"questionId\\\":\\\"1.7\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"7. A security architect argues: \\\\\\\"We are adopting Zero Trust, so internal traffic no longer needs\\\\nsegmentation because every user is authenticated.\\\\\\\" Which response best reflects the lecture\'s\\\\nview of ZTA components?\\\\nA. Correct: strong identity verification alone eliminates lateral movement\\\\nB. Incorrect: ZTA emphasizes continuous verification and micro-segmentation to limit lateral\\\\nmovement even after authentication\\\\nC. Correct: ZTA assumes a trusted internal network once MFA is enabled\\\\nD. Incorrect: ZTA replaces authorization with auditing\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"(B) Incorrect: ZTA emphasizes continuous verification and micro-segmentation to limit lateral\\\\nmovement even after authentication\\\"},{\\\"questionId\\\":\\\"1.8\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"8. A database breach occurs because user input is concatenated directly into SQL queries. The\\\\ndeveloper claims they can \\\\\\\"sanitize dangerous characters\\\\\\\" and be safe. Which option best\\\\ncaptures the lecture\'s nuanced defense priority?\\\\nA. Sanitization is sufficient if the blacklist is long enough\\\\nB. Prepared statements are the primary defense because they separate code from data;\\\\nvalidation/sanitization are supporting controls\\\\nC. Input validation is unnecessary if hashing is used for integrity\\\\nD. Encryption of the database prevents SQL injection by hiding the tables\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"(B) Prepared statements are the primary defense because they separate code from data;\\\\nvalidation/sanitization are supporting controls\\\"},{\\\"questionId\\\":\\\"1.9\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"9. A company signs software updates. An attacker modifies the installer but keeps the original\\\\nvendor signature attached. Users\' systems reject the update. Which security goal is being\\\\nenforced most directly by the verification step described?\\\\nA. Availability, because updates keep systems running\\\\nB. Integrity and authenticity, because the signature verification fails after modification\\\\nC. Confidentiality, because the signature encrypts the installer\\\\nD. Access control, because only admins can run installers\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"(B) Integrity and authenticity, because the signature verification fails after modification\\\"},{\\\"questionId\\\":\\\"1.10\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"10. A team proposes keeping a proprietary encryption algorithm secret, arguing this will \\\\\\\"add\\\\nsecurity.\\\\\\\" Which statement best applies the lecture\'s principle-based reasoning?\\\\nA. This is recommended because secret algorithms reduce brute-force feasibility\\\\nB. This violates Kerckhoffs\'s Principle; security should rely on key secrecy, not hiding the\\\\nalgorithm\\\\nC. This is acceptable only for DES, not AES\\\\nD. This works if the key length is at least 56 bits\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"(B) This violates Kerckhoffs\'s Principle; security should rely on key secrecy, not hiding the\\\\nalgorithm\\\"},{\\\"questionId\\\":\\\"2.1\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"1. In the OSI Security Architecture, a security service (e.g., confidentiality) can be\\\\nachieved by multiple different mechanisms, so naming the mechanism alone\\\\n(e.g., encryption) does not fully specify the service being provided.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"2.2\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"2. Encrypting all network traffic is sufficient to eliminate the confidentiality risk\\\\nfrom traffic analysis because attackers cannot read message contents.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"False\\\"},{\\\"questionId\\\":\\\"2.3\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"3. A TCP SYN flood is best classified as an active denial-of-service attack because\\\\nit consumes server resources by maintaining many half-open connections.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"2.4\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"4. In the lecture\'s mapping of attacks to OSI layers, email spoofing is treated as\\\\nprimarily an application-layer issue rather than a transport-layer issue.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"2.5\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"5. Deploying SPF and DKIM without DMARC still provides value, but it can leave\\\\nambiguity in how receivers should handle messages that fail authentication\\\\nchecks.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"2.6\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"6. A replay attack can be mitigated solely by hashing the message content,\\\\nbecause any later re-sent message will produce a different hash value.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"False\\\"},{\\\"questionId\\\":\\\"2.7\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"7. In threat modeling, drawing a Data Flow Diagram (DFD) is not only\\\\ndocumentation; it helps reveal trust boundaries where security assumptions\\\\nchange and threats should be examined more carefully.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"2.8\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"8. SQL injection is fundamentally enabled when untrusted input is mixed with SQL\\\\ninstructions, so prepared statements directly address the root cause by\\\\nseparating data from code.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"2.9\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"9. In access control, replacing RBAC with ABAC necessarily reduces\\\\nadministrative complexity because ABAC policies are more flexible and dynamic.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"False\\\"},{\\\"questionId\\\":\\\"2.10\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"10. Under Kerckhoffs\'s Principle, publishing the encryption algorithm does not\\\\nweaken a system\'s security if the key remains secret and the algorithm is strong.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"3\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"Explain the relationship between security attacks, security mechanisms, and\\\\nsecurity services in the OSI Security Architecture, and justify why confusing\\\\nmechanisms with services leads to flawed security design?\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"Attacks are what adversaries do, mechanisms are the tools used to defend (e.g.,\\\\nencryption), and services are the protections delivered (e.g., confidentiality). If you treat\\\\na mechanism as a service, you may \\\\\\\"deploy a tool\\\\\\\" without ensuring the intended\\\\nprotection is actually achieved in the system context.\\\"},{\\\"questionId\\\":\\\"4\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"The OSI Security Architecture separates attacks, mechanisms, and services.\\\\na) Analyze why confusing a security mechanism with a security service can lead to flawed\\\\nsystem design.\\\\nb) Explain how the same mechanism may contribute to different security services\\\\ndepending on context.\\\\nc) Evaluate why this separation is useful when analyzing new or unfamiliar attacks.\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"a) Treating a \\\\\\\"service\\\\\\\" (goal) as if it were a “mechanism” (tool) can cause designers to deploy\\\\ncontrols without ensuring the intended protection is achieved. For example, \\\\\\\"confidentiality\\\\\\\" is\\\\na service goal; encryption is a mechanism—using the wrong framing can leave gaps.\\\\nb) Encryption can provide a confidentiality service for data in transit, and it can also support\\\\naccess control in certain workflows by protecting tokens/credentials. The same tool contributes\\\\nto different services depending on what it protects and how it is integrated.\\\\nc) It enables systematic reasoning: classify what the attacker is doing (attack), what protection\\\\nyou need (service), and what implements it (mechanism). This reduces ad-hoc fixes and\\\\nsupports consistent security analysis across different systems.\\\"},{\\\"questionId\\\":\\\"5\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"A system encrypts all user communications but performs no traffic padding.\\\\na) Analyze which type of passive attack remains feasible and why.\\\\nb) Explain which CIA property is threatened even though encryption is correctly applied.\\\\nc) Evaluate why encryption alone does not fully guarantee confidentiality in this scenario.\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"a) Traffic analysis remains feasible because an observer can infer who communicates with\\\\nwhom, how often, and message sizes/timing even if contents are encrypted. The attacker learns\\\\npatterns rather than plaintext.\\\\nb) Confidentiality is threatened because metadata can reveal sensitive information\\\\n(relationships, activity levels, operational rhythms) despite content secrecy. This is still a\\\\nconfidentiality leakage channel.\\\\nc) Encryption protects message contents, not necessarily communication patterns. Without\\\\ntraffic padding, observable metadata can still disclose meaningful information about users or\\\\noperations.\\\"},{\\\"questionId\\\":\\\"6\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"Analyze how attack surfaces (software, human, and network) differ, and explain\\\\nwhy reducing only one of them is insufficient for securing a system.\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"Software attack surface is exploitable code and components (bugs, unpatched\\\\nlibraries), human attack surface is user behavior (phishing, weak passwords), and\\\\nnetwork attack surface is exposure in connectivity (open ports, misconfigurations,\\\\nunencrypted traffic). Focusing on only one leaves other entry points open, so attackers\\\\ncan simply shift to the weakest remaining surface.\\\"},{\\\"questionId\\\":\\\"7\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"Compare replay attacks and masquerade attacks, and explain how authentication\\\\nmechanisms address these threats differently.\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"Masquerade is pretending to be a legitimate entity, while replay is re-sending a previously valid\\\\nmessage to gain unauthorized effect. Authentication helps detect masquerade by verifying\\\\nidentity, and it helps stop replay by ensuring freshness so old captured messages are rejected.\\\"},{\\\"questionId\\\":\\\"8\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"During threat modeling of a student portal, a Data Flow Diagram (DFD) reveals a\\\\ntrust boundary between users and the authentication service.\\\\na) Explain why trust boundaries are focal points for threat identification.\\\\nb) Analyze which STRIDE threat categories are most relevant at this boundary.\\\\nc) Justify how adding MFA changes the threat landscape.\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"a) Trust boundaries mark where security assumptions change (e.g., untrusted user environment\\\\nto trusted server environment). This is where attackers can inject malicious inputs or\\\\nimpersonate entities.\\\\nb) Spoofing is highly relevant (attempts to impersonate another student), and DoS is relevant\\\\n(overwhelming authentication requests). Repudiation can also arise if actions are not auditable,\\\\nbut the boundary primarily stresses authentication and availability risks.\\\\nc) MFA raises the cost of spoofing because possession of a password alone is insufficient to\\\\nauthenticate. It reduces the feasibility of credential-based impersonation, shifting attacker\\\\nfocus to other vectors.\\\"},{\\\"questionId\\\":\\\"9\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"A web application validates user input but does not use prepared statements in its\\\\ndatabase queries.\\\\na) Analyze why SQL injection may still be possible in this design.\\\\nb) Explain how prepared statements address the root cause of SQL injection.\\\\nc) Evaluate why relying solely on validation and sanitization is risky.\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"a) Validation alone can miss edge cases or bypasses, and if untrusted input is still concatenated\\\\ninto SQL strings, an attacker may inject control characters or logic. The core risk remains:\\\\nmixing data with executable query structure.\\\\nb) Prepared statements separate code (SQL structure) from data (parameters), preventing user\\\\ninput from being interpreted as SQL syntax. The database treats parameters strictly as values,\\\\nblocking injected operators like \' OR 1=1 --.\\\\nc) Validation/sanitization is error-prone and inconsistent across features and encodings; one\\\\nmissed path can reintroduce the vulnerability. Prepared statements provide a stronger,\\\\nsystematic control that does not rely on perfect filtering.\\\"},{\\\"questionId\\\":\\\"10\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"An organization adopts Attribute-Based Access Control (ABAC) instead of Role-\\\\nBased Access Control (RBAC).\\\\na) Compare how access decisions are made differently in ABAC versus RBAC.\\\\nb) Analyze why ABAC can enforce more fine-grained policies.\\\\nc) Evaluate the trade-off introduced by ABAC in terms of system complexity.\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"a) RBAC grants access based on predefined roles and their permissions, while ABAC makes\\\\ndecisions using multiple attributes such as user, resource, action, and environment.\\\\nb) ABAC supports fine-grained control because it can combine several conditions in one policy,\\\\nallowing context-aware access rules that roles alone cannot express easily.\\\\nc) The trade-off is increased complexity, since ABAC requires managing many attributes and\\\\nevaluating policies dynamically, which raises administrative and computational overhead.\\\"},{\\\"questionId\\\":\\\"11\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"A secure system uses AES for bulk data encryption and RSA only during session\\\\nsetup.\\\\na) Explain why RSA is unsuitable for encrypting large volumes of data.\\\\nb) Analyze how combining symmetric and asymmetric cryptography solves multiple\\\\nsecurity problems.\\\\nc) Justify why this hybrid approach is standard in protocols like TLS.\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"a) RSA is computationally expensive and designed for small messages; encrypting large data\\\\ndirectly is inefficient and often impractical. The lecture explicitly notes RSA\'s slowness and\\\\nlimited payload suitability.\\\\nb) RSA securely exchanges a symmetric session key (solving key distribution), while AES\\\\nefficiently encrypts bulk data once the shared key exists. This combines secure setup with fast\\\\nongoing confidentiality.\\\\nc) This hybrid approach provides secure key exchange and fast data encryption, which is why it\\\\nis used in TLS.\\\"},{\\\"questionId\\\":\\\"12\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"An organization deploys autonomous Al agents to monitor systems and\\\\nautomatically remediate threats.\\\\na) Analyze how agent autonomy can improve detection and response speed.\\\\nb) Explain one risk introduced by chained or cross-agent behavior.\\\\nc) Evaluate why human oversight remains necessary even with Agentic Al in place.\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"a) Faster detection/response: Agents monitor 24/7, auto-triage alerts, and execute\\\\ncontainment immediately cutting human wait time and scaling across many systems.\\\\nb) Chaining risk: A mistake or compromise in one agent can feed wrong signals to others,\\\\ncausing cascaded actions (e.g., privilege escalation through trust links).\\\\nc) Why humans still needed: To approve/override high-impact actions, enforce\\\\npolicy/governance, audit decisions, and prevent/contain cascading failures or unintended data\\\\nexposure.\\\"}]\"', 'MIXED', 'https://ai-exam-grader-pdfs.s3.eu-central-1.amazonaws.com/model-answers/cmksw8ren00017khcjonxabsg/model-answer.pdf', 1, '2026-01-24 22:41:06.222', '2026-01-24 22:41:07.016', 'clcourse003', 'cmhfehuu200027kic5hrxn5rm', '2026-01-26 00:00:00.000');
INSERT INTO `exams` (`id`, `title`, `duration`, `questions`, `type`, `modelAnswerFile`, `isActive`, `createdAt`, `updatedAt`, `courseId`, `instructorId`, `examDate`) VALUES
('cmkvbc4yj00017k6sr6eermq1', 'Test Final', NULL, '\"[{\\\"questionId\\\":\\\"1.1\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"An employee receives a highly personalized email that references internal projects and comes from an address that visually matches a trusted domain. The attacker succeeded by exploiting human behavior, not a software bug. From the lecture\'s perspective, which statement best explains why this attack is difficult to prevent using technical controls alone?\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"B. Phishing targets the human attack surface, which remains vulnerable even when systems are technically secure\\\"},{\\\"questionId\\\":\\\"1.2\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"You are threat-modeling a student portal. A developer claims: \\\\\\\"If we encrypt all traffic, we have solved confidentiality, integrity, and authentication.\\\\\\\" Which critique best matches the lecture\'s separation of services and mechanisms?\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"A. Encryption is a mechanism mainly for confidentiality; integrity and authentication require additional mechanisms/services (e.g., hashes/MACs, signatures, authentication exchange)\\\"},{\\\"questionId\\\":\\\"1.3\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"A SOC analyst observes encrypted traffic between a user and a server but infers sensitive operational details from who communicates, when, and how much. Which pairing is most accurate?\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"B. Passive attack; traffic analysis; threatens confidentiality\\\"},{\\\"questionId\\\":\\\"1.4\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"During an incident, thousands of TCP connections are stuck in a \\\\\\\"pending\\\\\\\" state because clients sent SYNs but never completed the handshake. Which statement is the best conceptual classification across the lecture\'s frameworks?\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"B. It is an active attack (DoS) targeting availability by exploiting half-open TCP state\\\"},{\\\"questionId\\\":\\\"1.5\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"A team wants to prevent replay of a captured \\\\\\\"valid login request\\\\\\\" in a wireless access system. Which mechanism/service alignment best matches the lecture’s recap logic?\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"B. Authentication service using authentication exchange (e.g., challenge–response/OTP), because freshness is verified\\\"},{\\\"questionId\\\":\\\"1.6\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"An organization uses RBAC and ABAC together. A user is assigned the role \\\\\\\"Doctor\\\\\\\" (RBAC), but access is granted only if the device is patched and the login is from the local network (ABAC). What is the most accurate interpretation?\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"B. ABAC is enforcing fine-grained, context-dependent constraints on top of role-based permissions\\\"},{\\\"questionId\\\":\\\"1.7\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"A security architect argues: \\\\\\\"We are adopting Zero Trust, so internal traffic no longer needs segmentation because every user is authenticated.\\\\\\\" Which response best reflects the lecture’s view of ZTA components?\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"B. Incorrect: ZTA emphasizes continuous verification and micro-segmentation to limit lateral movement even after authentication\\\"},{\\\"questionId\\\":\\\"1.8\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"A database breach occurs because user input is concatenated directly into SQL queries. The developer claims they can \\\\\\\"sanitize dangerous characters\\\\\\\" and be safe. Which option best captures the lecture’s nuanced defense priority?\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"B. Prepared statements are the primary defense because they separate code from data; validation/sanitization are supporting controls\\\"},{\\\"questionId\\\":\\\"1.9\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"A company signs software updates. An attacker modifies the installer but keeps the original vendor signature attached. Users’ systems reject the update. Which security goal is being enforced most directly by the verification step described?\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"B. Integrity and authenticity, because the signature verification fails after modification\\\"},{\\\"questionId\\\":\\\"1.10\\\",\\\"type\\\":\\\"MCQ\\\",\\\"question\\\":\\\"A team proposes keeping a proprietary encryption algorithm secret, arguing this will \\\\\\\"add security.\\\\\\\" Which statement best applies the lecture\'s principle-based reasoning?\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"B. This violates Kerckhoffs\'s Principle; security should rely on key secrecy, not hiding the algorithm\\\"},{\\\"questionId\\\":\\\"2.1\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"In the OSI Security Architecture, a security service (e.g., confidentiality) can be achieved by multiple different mechanisms, so naming the mechanism alone (e.g., encryption) does not fully specify the service being provided.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"2.2\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"Encrypting all network traffic is sufficient to eliminate the confidentiality risk from traffic analysis because attackers cannot read message contents.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"False\\\"},{\\\"questionId\\\":\\\"2.3\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"A TCP SYN flood is best classified as an active denial-of-service attack because it consumes server resources by maintaining many half-open connections.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"2.4\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"In the lecture\'s mapping of attacks to OSI layers, email spoofing is treated as primarily an application-layer issue rather than a transport-layer issue.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"2.5\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"Deploying SPF and DKIM without DMARC still provides value, but it can leave ambiguity in how receivers should handle messages that fail authentication checks.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"2.6\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"A replay attack can be mitigated solely by hashing the message content, because any later re-sent message will produce a different hash value.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"False\\\"},{\\\"questionId\\\":\\\"2.7\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"In threat modeling, drawing a Data Flow Diagram (DFD) is not only documentation; it helps reveal trust boundaries where security assumptions change and threats should be examined more carefully.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"2.8\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"SQL injection is fundamentally enabled when untrusted input is mixed with SQL instructions, so prepared statements directly address the root cause by separating data from code.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"2.9\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"In access control, replacing RBAC with ABAC necessarily reduces administrative complexity because ABAC policies are more flexible and dynamic.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"False\\\"},{\\\"questionId\\\":\\\"2.10\\\",\\\"type\\\":\\\"TrueFalse\\\",\\\"question\\\":\\\"Under Kerckhoffs\'s Principle, publishing the encryption algorithm does not weaken a system\'s security if the key remains secret and the algorithm is strong.\\\",\\\"questionGrade\\\":1,\\\"answer\\\":\\\"True\\\"},{\\\"questionId\\\":\\\"3.1\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"Explain the relationship between security attacks, security mechanisms, and security services in the OSI Security Architecture, and justify why confusing mechanisms with services leads to flawed security design?\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"Attacks are what adversaries do, mechanisms are the tools used to defend (e.g., encryption), and services are the protections delivered (e.g., confidentiality). If you treat a mechanism as a service, you may \\\\\\\"deploy a tool\\\\\\\" without ensuring the intended protection is actually achieved in the system context.\\\"},{\\\"questionId\\\":\\\"4.1\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"The OSI Security Architecture separates attacks, mechanisms, and services. a) Analyze why confusing a security mechanism with a security service can lead to flawed system design.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"Treating a \\\\\\\"service\\\\\\\" (goal) as if it were a \\\\\\\"mechanism\\\\\\\" (tool) can cause designers to deploy controls without ensuring the intended protection is achieved. For example, \\\\\\\"confidentiality\\\\\\\" is a service goal; encryption is a mechanism—using the wrong framing can leave gaps.\\\"},{\\\"questionId\\\":\\\"4.2\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"The OSI Security Architecture separates attacks, mechanisms, and services. b) Explain how the same mechanism may contribute to different security services depending on context.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"Encryption can provide a confidentiality service for data in transit, and it can also support access control in certain workflows by protecting tokens/credentials. The same tool contributes to different services depending on what it protects and how it is integrated.\\\"},{\\\"questionId\\\":\\\"4.3\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"The OSI Security Architecture separates attacks, mechanisms, and services. c) Evaluate why this separation is useful when analyzing new or unfamiliar attacks.\\\",\\\"questionGrade\\\":0.66,\\\"answer\\\":\\\"It enables systematic reasoning: classify what the attacker is doing (attack), what protection you need (service), and what implements it (mechanism). This reduces ad-hoc fixes and supports consistent security analysis across different systems.\\\"},{\\\"questionId\\\":\\\"5.1\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"A system encrypts all user communications but performs no traffic padding. a) Analyze which type of passive attack remains feasible and why.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"Traffic analysis remains feasible because an observer can infer who communicates with whom, how often, and message sizes/timing even if contents are encrypted. The attacker learns patterns rather than plaintext.\\\"},{\\\"questionId\\\":\\\"5.2\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"A system encrypts all user communications but performs no traffic padding. b) Explain which CIA property is threatened even though encryption is correctly applied.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"Confidentiality is threatened because metadata can reveal sensitive information (relationships, activity levels, operational rhythms) despite content secrecy. This is still a confidentiality leakage channel.\\\"},{\\\"questionId\\\":\\\"5.3\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"A system encrypts all user communications but performs no traffic padding. c) Evaluate why encryption alone does not fully guarantee confidentiality in this scenario.\\\",\\\"questionGrade\\\":0.66,\\\"answer\\\":\\\"Encryption protects message contents, not necessarily communication patterns. Without traffic padding, observable metadata can still disclose meaningful information about users or operations.\\\"},{\\\"questionId\\\":\\\"6.1\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"Analyze how attack surfaces (software, human, and network) differ, and explain why reducing only one of them is insufficient for securing a system.\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"Software attack surface is exploitable code and components (bugs, unpatched libraries), human attack surface is user behavior (phishing, weak passwords), and network attack surface is exposure in connectivity (open ports, misconfigurations, unencrypted traffic). Focusing on only one leaves other entry points open, so attackers can simply shift to the weakest remaining surface.\\\"},{\\\"questionId\\\":\\\"7.1\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"Compare replay attacks and masquerade attacks, and explain how authentication mechanisms address these threats differently.\\\",\\\"questionGrade\\\":2,\\\"answer\\\":\\\"Masquerade is pretending to be a legitimate entity, while replay is re-sending a previously valid message to gain unauthorized effect. Authentication helps detect masquerade by verifying identity, and it helps stop replay by ensuring freshness so old captured messages are rejected.\\\"},{\\\"questionId\\\":\\\"8.1\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"During threat modeling of a student portal, a Data Flow Diagram (DFD) reveals a trust boundary between users and the authentication service. a) Explain why trust boundaries are focal points for threat identification.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"Trust boundaries mark where security assumptions change (e.g., untrusted user environment to trusted server environment). This is where attackers can inject malicious inputs or impersonate entities.\\\"},{\\\"questionId\\\":\\\"8.2\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"During threat modeling of a student portal, a Data Flow Diagram (DFD) reveals a trust boundary between users and the authentication service. b) Analyze which STRIDE threat categories are most relevant at this boundary.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"Spoofing is highly relevant (attempts to impersonate another student), and DoS is relevant (overwhelming authentication requests). Repudiation can also arise if actions are not auditable, but the boundary primarily stresses authentication and availability risks.\\\"},{\\\"questionId\\\":\\\"8.3\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"During threat modeling of a student portal, a Data Flow Diagram (DFD) reveals a trust boundary between users and the authentication service. c) Justify how adding MFA changes the threat landscape.\\\",\\\"questionGrade\\\":0.66,\\\"answer\\\":\\\"MFA raises the cost of spoofing because possession of a password alone is insufficient to authenticate. It reduces the feasibility of credential-based impersonation, shifting attacker focus to other vectors.\\\"},{\\\"questionId\\\":\\\"9.1\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"A web application validates user input but does not use prepared statements in its database queries. a) Analyze why SQL injection may still be possible in this design.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"Validation alone can miss edge cases or bypasses, and if untrusted input is still concatenated into SQL strings, an attacker may inject control characters or logic. The core risk remains: mixing data with executable query structure.\\\"},{\\\"questionId\\\":\\\"9.2\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"A web application validates user input but does not use prepared statements in its database queries. b) Explain how prepared statements address the root cause of SQL injection.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"Prepared statements separate code (SQL structure) from data (parameters), preventing user input from being interpreted as SQL syntax. The database treats parameters strictly as values, blocking injected operators like \' OR 1=1 --.\\\"},{\\\"questionId\\\":\\\"9.3\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"A web application validates user input but does not use prepared statements in its database queries. c) Evaluate why relying solely on validation and sanitization is risky.\\\",\\\"questionGrade\\\":0.66,\\\"answer\\\":\\\"Validation/sanitization is error-prone and inconsistent across features and encodings; one missed path can reintroduce the vulnerability. Prepared statements provide a stronger, systematic control that does not rely on perfect filtering.\\\"},{\\\"questionId\\\":\\\"10.1\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"An organization adopts Attribute-Based Access Control (ABAC) instead of Role-Based Access Control (RBAC). a) Compare how access decisions are made differently in ABAC versus RBAC.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"RBAC grants access based on predefined roles and their permissions, while ABAC makes decisions using multiple attributes such as user, resource, action, and environment.\\\"},{\\\"questionId\\\":\\\"10.2\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"An organization adopts Attribute-Based Access Control (ABAC) instead of Role-Based Access Control (RBAC). b) Analyze why ABAC can enforce more fine-grained policies.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"ABAC supports fine-grained control because it can combine several conditions in one policy, allowing context-aware access rules that roles alone cannot express easily.\\\"},{\\\"questionId\\\":\\\"10.3\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"An organization adopts Attribute-Based Access Control (ABAC) instead of Role-Based Access Control (RBAC). c) Evaluate the trade-off introduced by ABAC in terms of system complexity.\\\",\\\"questionGrade\\\":0.66,\\\"answer\\\":\\\"The trade-off is increased complexity, since ABAC requires managing many attributes and evaluating policies dynamically, which raises administrative and computational overhead.\\\"},{\\\"questionId\\\":\\\"11.1\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"A secure system uses AES for bulk data encryption and RSA only during session setup. a) Explain why RSA is unsuitable for encrypting large volumes of data.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"RSA is computationally expensive and designed for small messages; encrypting large data directly is inefficient and often impractical. The lecture explicitly notes RSA\'s slowness and limited payload suitability.\\\"},{\\\"questionId\\\":\\\"11.2\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"A secure system uses AES for bulk data encryption and RSA only during session setup. b) Analyze how combining symmetric and asymmetric cryptography solves multiple security problems.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"RSA securely exchanges a symmetric session key (solving key distribution), while AES efficiently encrypts bulk data once the shared key exists. This combines secure setup with fast ongoing confidentiality.\\\"},{\\\"questionId\\\":\\\"11.3\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"A secure system uses AES for bulk data encryption and RSA only during session setup. c) Justify why this hybrid approach is standard in protocols like TLS.\\\",\\\"questionGrade\\\":0.66,\\\"answer\\\":\\\"This hybrid approach provides secure key exchange and fast data encryption, which is why it is used in TLS.\\\"},{\\\"questionId\\\":\\\"12.1\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"An organization deploys autonomous AI agents to monitor systems and automatically remediate threats. a) Analyze how agent autonomy can improve detection and response speed.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"Faster detection/response: Agents monitor 24/7, auto-triage alerts, and execute containment immediately cutting human wait time and scaling across many systems.\\\"},{\\\"questionId\\\":\\\"12.2\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"An organization deploys autonomous AI agents to monitor systems and automatically remediate threats. b) Explain one risk introduced by chained or cross-agent behavior.\\\",\\\"questionGrade\\\":0.67,\\\"answer\\\":\\\"Chaining risk: A mistake or compromise in one agent can feed wrong signals to others, causing cascaded actions (e.g., privilege escalation through trust links).\\\"},{\\\"questionId\\\":\\\"12.3\\\",\\\"type\\\":\\\"Short-Answer\\\",\\\"question\\\":\\\"An organization deploys autonomous AI agents to monitor systems and automatically remediate threats. c) Evaluate why human oversight remains necessary even with Agentic AI in place.\\\",\\\"questionGrade\\\":0.66,\\\"answer\\\":\\\"Why humans still needed: To approve/override high-impact actions, enforce policy/governance, audit decisions, and prevent/contain cascading failures or unintended data exposure.\\\"}]\"', 'MIXED', 'https://ai-exam-grader-pdfs.s3.eu-central-1.amazonaws.com/model-answers/cmkvbc4yj00017k6sr6eermq1/model-answer.pdf', 1, '2026-01-26 15:19:10.361', '2026-01-26 15:19:11.135', 'clcourse001', 'cmhfehuu200027kic5hrxn5rm', '2026-01-26 00:00:00.000');

